import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', msg: '' });
  return (
    <form>
      <input onChange={(e) => setForm({...form, name: e.target.value})} />
      <textarea onChange={(e) => setForm({...form, msg: e.target.value})} />
    </form>
  );
};

